and created_at < #{end}

mapper.select:
select * from comments

order by created_at desc, id desc
limit #{limit} offset #{offset}

mapper.insert:
insert into comments (
  target_type, target_key, parent_id, content, nickname, email, website, avatar, location, browser, os
) values (
  #{targetType}, #{targetKey}, #{parentId}, #{content}, #{nickname}, #{email}, #{website}, #{avatar},
  #{location}, #{browser}, #{os}
)

mapper.update:
update comments
set status = case when status = 1 then 0 else 1 end
where id = #{id}

update comments
set is_deleted = true, deleted_at = current_timestamp
where id = #{id}
